data.content:
Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_On500()
    {
        var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellationToken()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.OK));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_TimesOut_WithSlowResponse()
    {
        // Handler that simulates a slow server
        var handler = new DelayHandler(TimeSpan.FromSeconds(10));
        var fetcher = new DataFetcher(new HttpClient(handler) { Timeout = TimeSpan.FromMilliseconds(50) });

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // --- Test helpers ---

    private class MockHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        public MockHandler(HttpResponseMessage response) => _response = response;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(_response);
        }
    }

    private class DelayHandler : HttpMessageHandler
    {
        private readonly TimeSpan _delay;
        public DelayHandler(TimeSpan delay) => _delay = delay;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(_delay, cancellationToken);
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key points:**

- **Mock at `HttpMessageHandler`**, not `HttpClient` — this is the standard seam for testing HTTP calls without a real network.
- **Pre-cancel** the `CancellationTokenSource` to test cancellation synchronously and deterministically.
- **For timeouts**, set `HttpClient.Timeout` low and use a `DelayHandler` — `HttpClient` internally cancels via `TaskCanceledException`, same as real timeout behavior.
- **`[TestMethod]` + `async Task`** — MSTest natively awaits async tests; never use `async void`.
